// This is a simplified example. Real implementation would check:
// - If already connected
// - Recent activity/posts
// - Mutual connections
// - Profile completeness

const contacts = $input.all();

const today = new Date().toISOString().split('T')[0];
const maxDaily = 15;

// Filter contacts not yet approached on LinkedIn
const viable = contacts.filter(item => {
  const lastContact = item.json.last_contact || '';
  return !lastContact.startsWith(today);
});

return viable.slice(0, maxDaily);

