const contactData = $node["Get LinkedIn Prospects"].json;
const connectionNote = $json.message.content.trim();

return {
  ...contactData,
  linkedin_note: connectionNote.substring(0, 280),
  linkedin_action: 'send_connection_request',
  relationship_stage: 'LinkedIn - Connection Sent',
  last_contact: new Date().toISOString(),
  notes: (contactData.notes || '') + ' | LinkedIn connection request queued'
};

