const followUpDate = new Date(Date.now() + 2 * 24 * 60 * 60 * 1000);

return {
  ...$input.first().json,
  linkedin_follow_up_due: followUpDate.toISOString(),
  next_action: 'Check if connection accepted → Send value message'
